{
  "name": "Athenaeum Digital Curator",
  "description": "An elegant and minimalistic digital library manager featuring a curated collection of classics and modern fiction, with full admin controls for catalog management."
}

export interface Book {
  id: string;
  title: string;
  author: string;
  genre: string;
  coverUrl: string;
  synopsis: string;
  published: string;
  pages: number;
  isbn: string;
  stock: number;
  rating: number;
}

export type ViewState = 'HOME' | 'ADMIN';

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element to mount to");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { Book, ViewState } from './types';
import Sidebar from './components/Sidebar';
import BookCard from './components/BookCard';
import BookDetails from './components/BookDetails';
import AdminPanel from './components/AdminPanel';
import LoginModal from './components/LoginModal';

const INITIAL_BOOKS: Book[] = [
  {
    id: '1',
    title: 'The Silent Patient',
    author: 'Alex Michaelides',
    genre: 'Modern Fiction',
    coverUrl: 'https://picsum.photos/seed/silent/400/600',
    synopsis: "Alicia Berenson’s life is seemingly perfect. A famous painter married to an in-demand fashion photographer, she lives in a grand house with big windows overlooking a park in one of London’s most desirable areas. One evening her husband Gabriel returns home late, and Alicia shoots him five times in the face, and then never speaks another word.",
    published: 'February 2019',
    pages: 336,
    isbn: '9781250301697',
    stock: 5,
    rating: 4.5,
  },
  {
    id: '2',
    title: 'The Great Gatsby',
    author: 'F. Scott Fitzgerald',
    genre: 'Classics',
    coverUrl: 'https://picsum.photos/seed/gatsby/400/600',
    synopsis: "The story of the mysteriously wealthy Jay Gatsby and his love for the beautiful Daisy Buchanan.",
    published: 'April 1925',
    pages: 180,
    isbn: '9780743273565',
    stock: 3,
    rating: 5,
  },
  {
    id: '3',
    title: 'Metamorphosis',
    author: 'Franz Kafka',
    genre: 'Classics',
    coverUrl: 'https://picsum.photos/seed/kafka/400/600',
    synopsis: "The story of salesman Gregor Samsa, who wakes one morning to find himself inexplicably transformed into a huge insect.",
    published: '1915',
    pages: 100,
    isbn: '9780553213690',
    stock: 2,
    rating: 4.8,
  }
];

const App: React.FC = () => {
  const [books, setBooks] = useState<Book[]>(() => {
    const saved = localStorage.getItem('athenaeum_books');
    return saved ? JSON.parse(saved) : INITIAL_BOOKS;
  });
  const [selectedBook, setSelectedBook] = useState<Book | null>(null);
  const [view, setView] = useState<ViewState>('HOME');
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [notification, setNotification] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('athenaeum_books', JSON.stringify(books));
  }, [books]);

  const handleAddBook = (newBook: Book) => {
    setBooks(prev => [newBook, ...prev]);
    setNotification('Book successfully added to the collection.');
  };

  const handleBorrow = (bookId: string) => {
    setBooks(prev => prev.map(b => {
      if (b.id === bookId && b.stock > 0) {
        setNotification(`Confirmation email sent! Please return "${b.title}" within 7 days to avoid a fine.`);
        return { ...b, stock: b.stock - 1 };
      }
      return b;
    }));
  };

  const handleLogin = (success: boolean) => {
    if (success) {
      setIsAdmin(true);
      setShowLogin(false);
      setView('ADMIN');
    }
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setView('HOME');
  };

  return (
    <div className="flex h-screen overflow-hidden selection:bg-primary/20">
      <Sidebar 
        currentView={view} 
        onViewChange={setView} 
        isAdmin={isAdmin}
        onLoginClick={() => setShowLogin(true)}
        onLogout={handleLogout}
        genres={Array.from(new Set(books.map(b => b.genre)))}
        authors={Array.from(new Set(books.map(b => b.author)))}
      />

      <main className="flex-1 overflow-y-auto p-8 md:p-12 relative">
        <header className="mb-12">
          <h2 className="text-4xl font-light text-ink">{view === 'HOME' ? 'Our Collection' : 'Curator Panel'}</h2>
          <p className="text-primary/60 italic mt-1">
            {view === 'HOME' 
              ? `Displaying ${books.length} curated works` 
              : 'Add and manage the library catalog'}
          </p>
        </header>

        {view === 'HOME' ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-10">
            {books.map(book => (
              <BookCard 
                key={book.id} 
                book={book} 
                isSelected={selectedBook?.id === book.id}
                onClick={() => setSelectedBook(book)} 
              />
            ))}
          </div>
        ) : (
          <AdminPanel onAddBook={handleAddBook} />
        )}

        {/* Floating Notification */}
        {notification && (
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] bg-white border border-primary/20 shadow-2xl p-6 rounded-xl max-w-md animate-bounce">
            <div className="flex items-start gap-4">
              <span className="material-icons text-primary">mark_email_read</span>
              <div>
                <p className="text-sm font-medium text-ink">{notification}</p>
                <button 
                  onClick={() => setNotification(null)}
                  className="text-xs text-primary mt-2 font-bold uppercase tracking-widest hover:underline"
                >
                  Dismiss
                </button>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Details Side Panel */}
      {selectedBook && (
        <BookDetails 
          book={selectedBook} 
          onClose={() => setSelectedBook(null)}
          onBorrow={() => handleBorrow(selectedBook.id)}
        />
      )}

      {/* Login Modal */}
      {showLogin && (
        <LoginModal 
          onClose={() => setShowLogin(false)} 
          onLogin={handleLogin} 
        />
      )}
    </div>
  );
};

export default App;

