import React, { useState } from 'react';

interface FileUploadProps {
  onFileSelect: (base64: string) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [preview, setPreview] = useState<string | null>(null);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') setIsDragging(true);
    else if (e.type === 'dragleave') setIsDragging(false);
  };

  const processFile = (file: File) => {
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const result = e.target?.result as string;
        setPreview(result);
        onFileSelect(result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  };

  return (
    <div className="w-full">
      <div 
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        className={`relative aspect-[2/3] border-2 border-dashed rounded-xl transition-all flex flex-col items-center justify-center gap-4 overflow-hidden group ${
          isDragging ? 'border-primary bg-primary/5 scale-105' : 'border-primary/20 bg-vintage-beige/50'
        }`}
      >
        {preview ? (
          <>
            <img src={preview} className="absolute inset-0 w-full h-full object-cover" alt="Preview" />
            <div className="absolute inset-0 bg-ink/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-sm">
              <span className="text-white text-xs font-bold uppercase tracking-widest">Replace Cover</span>
            </div>
          </>
        ) : (
          <>
            <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center">
              <span className="material-icons text-primary">cloud_upload</span>
            </div>
            <div className="text-center px-4">
              <p className="text-sm font-bold text-ink">Drag & Drop Cover</p>
              <p className="text-[10px] text-ink/40 uppercase tracking-widest mt-1">or click to browse</p>
            </div>
          </>
        )}
        <input 
          type="file" 
          className="absolute inset-0 opacity-0 cursor-pointer" 
          onChange={handleInput} 
          accept="image/*"
        />
      </div>
    </div>
  );
};

export default FileUpload;

import React, { useState } from 'react';
import { Book } from '../types';
import FileUpload from './FileUpload';

interface AdminPanelProps {
  onAddBook: (book: Book) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onAddBook }) => {
  const [formData, setFormData] = useState<Partial<Book>>({
    title: '',
    author: '',
    genre: 'Modern Fiction',
    published: '',
    pages: 0,
    isbn: '',
    stock: 1,
    synopsis: '',
    coverUrl: '',
    rating: 5,
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.author || !formData.coverUrl) return;

    const newBook: Book = {
      ...formData as Book,
      id: Math.random().toString(36).substr(2, 9),
    };

    onAddBook(newBook);
    setFormData({
      title: '',
      author: '',
      genre: 'Modern Fiction',
      published: '',
      pages: 0,
      isbn: '',
      stock: 1,
      synopsis: '',
      coverUrl: '',
      rating: 5,
    });
  };

  return (
    <div className="max-w-5xl mx-auto bg-white/60 backdrop-blur-xl p-10 rounded-3xl border border-primary/10 shadow-xl animate-in fade-in zoom-in duration-500">
      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-12">
        <div className="space-y-6">
          <label className="block">
            <span className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">Book Cover</span>
            <FileUpload onFileSelect={(url) => setFormData(p => ({ ...p, coverUrl: url }))} />
          </label>
        </div>

        <div className="md:col-span-2 space-y-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div className="space-y-1">
              <label className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">Title</label>
              <input 
                required
                className="w-full bg-vintage-beige/50 border-none rounded-xl p-4 focus:ring-2 focus:ring-primary/20 italic" 
                placeholder="e.g. The Picture of Dorian Gray"
                value={formData.title}
                onChange={e => setFormData(p => ({ ...p, title: e.target.value }))}
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">Author</label>
              <input 
                required
                className="w-full bg-vintage-beige/50 border-none rounded-xl p-4 focus:ring-2 focus:ring-primary/20 italic" 
                placeholder="e.g. Oscar Wilde"
                value={formData.author}
                onChange={e => setFormData(p => ({ ...p, author: e.target.value }))}
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">Genre</label>
              <select 
                className="w-full bg-vintage-beige/50 border-none rounded-xl p-4 focus:ring-2 focus:ring-primary/20 italic appearance-none"
                value={formData.genre}
                onChange={e => setFormData(p => ({ ...p, genre: e.target.value }))}
              >
                <option>Modern Fiction</option>
                <option>Classics</option>
                <option>Poetry</option>
                <option>Philosophy</option>
                <option>Thriller</option>
              </select>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">Initial Stock</label>
              <input 
                type="number"
                min="0"
                className="w-full bg-vintage-beige/50 border-none rounded-xl p-4 focus:ring-2 focus:ring-primary/20 italic" 
                value={formData.stock}
                onChange={e => setFormData(p => ({ ...p, stock: parseInt(e.target.value) }))}
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">Published Date</label>
              <input 
                className="w-full bg-vintage-beige/50 border-none rounded-xl p-4 focus:ring-2 focus:ring-primary/20 italic" 
                placeholder="e.g. June 1890"
                value={formData.published}
                onChange={e => setFormData(p => ({ ...p, published: e.target.value }))}
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">ISBN</label>
              <input 
                className="w-full bg-vintage-beige/50 border-none rounded-xl p-4 focus:ring-2 focus:ring-primary/20 italic" 
                placeholder="9780000000000"
                value={formData.isbn}
                onChange={e => setFormData(p => ({ ...p, isbn: e.target.value }))}
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase tracking-widest font-bold text-ink/40 ml-1">Synopsis</label>
            <textarea 
              rows={4}
              className="w-full bg-vintage-beige/50 border-none rounded-xl p-4 focus:ring-2 focus:ring-primary/20 italic resize-none" 
              placeholder="Describe the soul of this work..."
              value={formData.synopsis}
              onChange={e => setFormData(p => ({ ...p, synopsis: e.target.value }))}
            />
          </div>

          <div className="pt-4 flex justify-end">
